What is the output of the following C code snippet?
#include <stdio.h>
int main() {
  char str[] = "JECA";
  printf("%zu", sizeof(str));
  return 0;
}

What will be the output of the following bitwise operation in C?
int x = 5;
printf("%d", x >> 1);

What is the output of the following macro evaluation?
#define MACRO(a, b) a*b
int main() {
  printf("%d", MACRO(2+3, 4));
  return 0;
}
